scwin.onpageload = function() {
    scwin.parent = $p.parent();

};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    $p.setTimeout(function() {
        $c.gus.cfEnableObj(acb_wrkIndictNo, false);
	    $c.gus.cfEnableObj(btn_readShift, false);

    }, {"delay":50});
};

//-------------------------------------------------------------------------
// Main저장 버튼 클릭
//-------------------------------------------------------------------------
scwin.f_main3Save = async function (){
    // if(ds_hidden.get("txt_check") == 0){
    if(ds_main3.getRowCount() == 0){
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002); // "조회결과가 존재하지 않습니다."
        return;
    }

    var modifyRowCnt = ds_main3.getModifiedIndex().length
    if (!(modifyRowCnt > 0)) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_001,["작업물량계획"]); // "@은(는) 변경된 사항이 없습니다."
        return;
    }
    for(var i = 0 ; i < ds_main3.getRowCount() ; i++){
        //  3 update
        if(ds_main3.getRowStatus(i) == "U") {	
            // 값이 변경된 경우
            // 변경된 Data의 기초값이 0 인 경우 신규입력 ( Status - 0:Normal, 1:Insert, 2:Delete, 3:Update, 4:Logical )
            if ( scwin.parent.ds_main3.getCellData(i, "wrkPlanQty") == 0 && scwin.parent.ds_main3.getCellData(i, "wrkPlanWt") == 0 
              && scwin.parent.ds_main3.getCellData(i, "wrkPlanCbm") == 0 ) {	// 기초 Data 가 없는경우
                // ds_main3.UserStatus(i) = 1;
                ds_main3.modifyRowStatus(i, "C");

            }else{	// 변경된 Data의 기초값이 0 이 아닌 경우 수정
                // ds_main3.UserStatus(i) = 3;
                ds_main3.modifyRowStatus(i, "U");

            }
            // 데이터를 삭제 한 경우 (변경 Data 가 0 이고, 기초 Data 가 0 이 아닌경우)
            if ( ds_main3.getCellData(i, "wrkPlanQty") == 0 && ds_main3.getCellData(i, "wrkPlanWt") == 0 
              && ds_main3.getCellData(i, "wrkPlanCbm") == 0 ) {	// 변경 Data 가 0 인 경우

                if (scwin.parent.ds_main3.getCellData(0, "wrkPlanQty") != 0 || scwin.parent.ds_main3.getCellData(0, "wrkPlanWt") != 0 
                 || scwin.parent.ds_main3.getCellData(0, "wrkPlanCbm") != 0 ) {	// 기초 Data 가 0 이 아닌경우
                    // ds_main3.UserStatus(i) = 2;
                    ds_main3.modifyRowStatus(i, "D");
                }
            }
            // 값이 변하였으나 기존 Data와 같은 값일 경우 return;
            if (scwin.parent.ds_main3.getCellData(i, "wrkPlanQty") == ds_main3.getCellData(i, "wrkPlanQty") 
             && scwin.parent.ds_main3.getCellData(i, "wrkPlanWt")  == ds_main3.getCellData(i, "wrkPlanWt") 
             && scwin.parent.ds_main3.getCellData(i, "wrkPlanCbm") == ds_main3.getCellData(i, "wrkPlanCbm")) {
                // ds_main3.UserStatus(i) = 0;
                ds_main3.modifyRowStatus(i, "R");
            }
        }
    }
    $c.sbm.execute(sbm_main3);
};

//-------------------------------------------------------------------------
// retrieve 조회 수행
//-------------------------------------------------------------------------
scwin.f_main3Retrieve = function (){
    ds_searchRetrieve3.set("wrkIndictNo",scwin.parent.txtWrkIndictNo.getValue());
    $c.sbm.execute(sbm_retrieve3);
};

//-------------------------------------------------------------------------
// 주간 Shift 계획 불러오기 버튼 클릭
//-------------------------------------------------------------------------
scwin.f_ShiftRetrieve = async function (){
	if (scwin.parent.lay_wrkIndictNo.getValue() == "") {
		await $c.gus.cfAlertMsg(MSG_CM_WRN_018, ["작업지시번호","작업지시번호 생성"]); //"@이(가) 존재하지 않습니다.\n먼저 @을(를) 하십시오."
		return;
	}
  	var wrkIndictNo = co_ds_combo1.getCellData(acb_wrkIndictNo.getSelectedIndex(), "code");
    ds_search.set("wrkIndictNo", wrkIndictNo);
    $c.sbm.execute(sbm_search);
};

//-------------------------------------------------------------------------
// 부두 조회(점소 선택시 해당 점소의 부두만 조회)
//-------------------------------------------------------------------------  
scwin.f_RetrievePierCd = async function (param1, param2) {
    ds_searchCombo1.set("sysCd", "DailyStevedoringWorkIndicationEBC");
    ds_searchCombo1.set("queryId", "retrieveWorkPlanListCombo");
    ds_searchCombo1.set("param1", param1);
    ds_searchCombo1.set("param2", param2);

    var rs = await $c.sbm.execute(sbm_retrievePierCd);
    if (rs.responseJSON.resultDataSet[0].Msg == "SUCC"){
        co_ds_combo1.setJSON(rs.responseJSON.GAUCE);

        if (co_ds_combo1.getRowCount() > 0){
            $c.gus.cfEnableObj(acb_wrkIndictNo, true);
            $c.gus.cfEnableObj(btn_readShift,true);
        }else{
            $c.gus.cfEnableObj(acb_wrkIndictNo,false);
            $c.gus.cfEnableObj(btn_readShift,false);
        }
        if(scwin.parent.ds_main2.getRowCount() > 0){
            if (scwin.parent.ds_main2.getCellData(0, "completeProcYn") == 1) {
                $c.gus.cfEnableObj(btn_readShift, false);
                gr_main3.setReadOnly("grid", true);
                // gr_main3.setColumnReadOnly("wrkPlanQty", true);
                // gr_main3.setColumnReadOnly("wrkPlanWt", true);
                // gr_main3.setColumnReadOnly("wrkPlanCbm", true);

            } else {
                $c.gus.cfEnableObj(btn_readShift, true);
                gr_main3.setReadOnly("grid", false);
                // gr_main3.setColumnReadOnly("wrkPlanQty", false);
                // gr_main3.setColumnReadOnly("wrkPlanWt", false);
                // gr_main3.setColumnReadOnly("wrkPlanCbm", false);
            }
        }
    };

};

//-------------------------------------------------------------------------
// 부두 조회(점소 선택시 해당 점소의 부두만 조회)
//-------------------------------------------------------------------------  
scwin.f_RetrievePierCdCall = function () {
    scwin.f_RetrievePierCd(scwin.parent.txt_hcvsslMgntNo.getValue(), scwin.parent.ds_main2.getCellData(0, "wrkIndictNo"));
};

scwin.btn_readShift_onclick = function (e) {
    scwin.f_ShiftRetrieve();
};

scwin.btn_save_onclick = function (e) {
    scwin.f_main3Save();
};

scwin.sbm_main3_submit = function (e) {

};

scwin.sbm_main3_submitdone = async function (e) {
    await $c.gus.cfAlertMsg(MSG_CM_INF_001);	// 성공적으로 저장하였습니다
  	scwin.f_main3Retrieve();

};

scwin.sbm_main3_submiterror = function (e) {

};

scwin.sbm_search_submit = function (e) {

};

scwin.sbm_search_submitdone = function (e) {
    for (var i = 0 ; i < ds_main3.getRowCount() ; i++) {
		ds_main3.setCellData(i, "wrkPlanQty", ds_main3Shift.getCellData(i,"wrkPlanQty"));
		ds_main3.setCellData(i, "wrkPlanWt", ds_main3Shift.getCellData(i,"wrkPlanWt"));
		ds_main3.setCellData(i, "wrkPlanCbm", ds_main3Shift.getCellData(i,"wrkPlanCbm"));

        scwin.parent.ds_main3.setCellData(i, "wrkPlanQty", ds_main3Shift.getCellData(i,"wrkPlanQty"));
		scwin.parent.ds_main3.setCellData(i, "wrkPlanWt", ds_main3Shift.getCellData(i,"wrkPlanWt"));
		scwin.parent.ds_main3.setCellData(i, "wrkPlanCbm", ds_main3Shift.getCellData(i,"wrkPlanCbm"));

	}

};

scwin.sbm_search_submiterror = function (e) {

};

scwin.sbm_retrieve3_submit = function (e) {

};

scwin.sbm_retrieve3_submitdone = function (e) {

};

scwin.sbm_retrieve3_submiterror = function (e) {

};

scwin.gr_main3_oneditend = function (rowIndex, columnIndex, value) {
    var colid = gr_main3.getColumnID(columnIndex);
    var olddata_wrkPlanQty  = ds_main3.getCellData(rowIndex, "wrkPlanQty");
    var olddata_wrkPlanWt   = ds_main3.getCellData(rowIndex, "wrkPlanWt");
    var olddata_wrkPlanCbm  = ds_main3.getCellData(rowIndex, "wrkPlanCbm");

    if (colid == "wrkPlanQty" && scwin.olddata_wrkPlanQty != olddata_wrkPlanQty) {
	 	scwin.olddata_wrkPlanQty = olddata_wrkPlanQty;
	} else if (colid == "wrkPlanWt" && scwin.olddata_wrkPlanWt != olddata_wrkPlanWt) {
	 	scwin.olddata_wrkPlanWt = olddata_wrkPlanWt;
	} else if (colid == "wrkPlanCbm" && scwin.olddata_wrkPlanCbm != olddata_wrkPlanCbm) {
		scwin.olddata_wrkPlanCbm = olddata_wrkPlanCbm;
	}
};

scwin.gr_main3_onafteredit = async function (rowIndex, columnIndex, value) {
    var colid = gr_main3.getColumnID(columnIndex);
    if (colid == "wrkPlanQty" && scwin.olddata_wrkPlanQty != ds_main3.getCellData(rowIndex, "wrkPlanQty")) {
	 	if (ds_main3.getCellData(rowIndex, colid) == 0) {
            ds_main3.setCellData(rowIndex, colid, 0);
			ds_main3.setCellData(rowIndex, "wrkPlanWt", 0);
			ds_main3.setCellData(rowIndex, "wrkPlanCbm", 0);
			return;
		} else {
			if (ds_main3.getCellData(rowIndex, "rmdrQty") < ds_main3.getCellData(rowIndex, "wrkPlanQty")) {
				if (!await $c.win.confirm("작업계획 수량 이(가) 잔여 수량 보다 많습니다. \n계속 진행하시겠습니까?")) {
					ds_main3.setCellData(rowIndex, 'wrkPlanQty', ds_main3.getCellData(rowIndex,'rmdrQty'));
                    gr_main3.setFocusedCell(rowIndex, "wrkPlanQty", true);
					return;
				}
			}
			var qty = ds_main3.getCellData(rowIndex, "rmdrQty");
			var vs = qty / ds_main3.getCellData(rowIndex, colid);
			ds_main3.setCellData(rowIndex, "wrkPlanWt", Math.round(ds_main3.getCellData(rowIndex,"rmdrWt") / vs * 1000) / 1000);
			ds_main3.setCellData(rowIndex, "wrkPlanCbm", Math.round(ds_main3.getCellData(rowIndex,"rmdrCbm") / vs * 1000) / 1000);
		}
	} else if (colid == "wrkPlanWt" && scwin.olddata_wrkPlanWt != ds_main3.getCellData(rowIndex,"wrkPlanWt")) {
        var validateValue = ds_main3.getCellData(rowIndex, colid);
        if (validateValue == 0) {
            ds_main3.setCellData(rowIndex, colid, 0);
        }
	 	// if(!cfValidateValue(ds_main3.getCellData(rowIndex,colid), "minNumber=0.000")){
        if (!$c.gus.isNum(validateValue) || 0 > parseInt(validateValue)) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_007,["중량(톤)"]);
            ds_main3.setCellData(rowIndex, colid, scwin.olddata_wrkPlanWt);
            return false;
        }
		if (ds_main3.getCellData(i, "rmdrWt") < ds_main3.getCellData(i, "wrkPlanWt")) {
			if (!await $c.win.confirm("작업계획 중량 이(가) 잔여 중량 보다 많습니다. \n계속 진행하시겠습니까?")) {
				ds_main3.setCellData(rowIndex, 'wrkPlanWt', ds_main3.getCellData(rowIndex, "rmdrWt"));
                gr_main3.setFocusedCell(rowIndex, "wrkPlanWt", true);
				return;
			}
		}
	} else if (colid == "wrkPlanCbm" && scwin.olddata_wrkPlanCbm != ds_main3.getCellData(rowIndex,"wrkPlanCbm")) {
        var validateValue = ds_main3.getCellData(rowIndex, colid);
        if (validateValue == 0) {
            ds_main3.setCellData(rowIndex, colid, 0);
        }
	 	// if(!cfValidateValue(ds_main3.getCellData(rowIndex,colid), "minNumber=0.000")){
        if (!$c.gus.isNum(validateValue) || 0 > parseInt(validateValue)) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_007,["CBM"]);
            ds_main3.setCellData(rowIndex, colid, scwin.olddata_wrkPlanCbm);
            return false;
        }
		if(ds_main3.getCellData(i, "rmdrCbm") < ds_main3.getCellData(i, "wrkPlanCbm")){
			if (!await $c.win.confirm("작업계획 CBM 이(가) 잔여 CBM 보다 많습니다. \n계속 진행하시겠습니까?")) {
				ds_main3.setCellData(rowIndex, 'wrkPlanCbm', ds_main3.getCellData(rowIndex, "rmdrCbm"));
                gr_main3.setFocusedCell(rowIndex, "wrkPlanCbm", true);
				return;
			}
		}
	}
};

